# Targets
#####################################################################################################

${BUILD_DIR}:
	@echo "Creating build directory at ${BUILD_DIR}"
	@mkdir -p ${BUILD_DIR}
	@echo "*" > ${BUILD_DIR}/.gitignore

${LOG_DIR}:
	@echo "Creating log directory at ${LOG_DIR}"
	@mkdir -p ${LOG_DIR}
	@echo "*" > ${LOG_DIR}/.gitignore

.PHONY: clean
clean:
	@echo "Cleaning build directory at ${BUILD_DIR}"
	@rm -rf ${BUILD_DIR}

